### 3. **פתרון בקוד (JavaScript)**  
```javascript
/**
 * בודק האם תיאור תקף (אורך ≤ 200 תווים)
 * @param {string} description - התיאור להדרכה
 * @returns {boolean} true אם האורך תקף, אחרת false
 */
function isValidDescription(description) {
  if (typeof description !== 'string') {
    throw new TypeError('Description must be a string');
  }
  return description.length <= 200;
}

// דוגמאות לשימוש:
console.log(isValidDescription("")); // true
console.log(isValidDescription("א" .repeat(200))); // true
console.log(isValidDescription("א" .repeat(201))); // false
console.log(isValidDescription("Hello, world!")); // true
```

> **הערה:** אם יש צורך ב-count מדויק של *characters* (למשל: לא לשבור אימוג'י לשני code units), נוכל להשתמש ב-`Array.from(description).length`:

```javascript
function isValidDescription(description) {
  if (typeof description !== 'string') {
    throw new TypeError('Description must be a string');
  }
  return Array.from(description).length <= 200;
}
```

